.dashboard-briefing-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 14px 20px 0;
}

.dashboard-briefing-header-left {
    display: flex;
    align-items: center;
    gap: 10px;
}

.dashboard-briefing-title {
    font-family: 'Playfair Display', serif;
    font-size: 15px;
    font-weight: 600;
    color: var(--text-primary, #1a1a1a);
    margin: 0;
}

.dashboard-briefing-date {
    font-family: 'Outfit', sans-serif;
    font-size: 12px;
    color: var(--text-secondary, #a1a1aa);
    font-weight: 400;
}

.dashboard-briefing-dismiss {
    background: none;
    border: none;
    cursor: pointer;
    color: var(--text-secondary, #a1a1aa);
    padding: 4px;
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s ease, color 0.15s ease;
}

.dashboard-briefing-dismiss:hover {
    background: rgba(0, 0, 0, 0.05);
    color: var(--text-primary, #1a1a1a);
}

/* ─── Content (stacked layout) ─── */

.dashboard-briefing-body {
    display: flex;
    flex-direction: column;
    padding: 14px 20px 16px;
    gap: 0;
}

/* ─── Divider ─── */

.dashboard-divider {
    height: 1px;
    background: var(--border-card);
    margin: 12px 0;
}

/* ─── Recap Section ─── */

.dashboard-recap {
    display: flex;
    flex-direction: column;
}

.dashboard-stat-row {
    display: flex;
    align-items: center;
    gap: 8px;
    cursor: pointer;
    padding: 2px 0;
    border-radius: 6px;
}

.dashboard-stat-line {
    font-family: 'Outfit', sans-serif;
    font-size: 13.5px;
    color: var(--text-secondary, #a1a1aa);
    line-height: 1.4;
}

.dashboard-stat-line strong {
    font-weight: 700;
    color: var(--text-primary, #1a1a1a);
    font-variant-numeric: tabular-nums;
}

.dashboard-recap-expand {
    background: none;
    border: none;
    cursor: pointer;
    color: var(--text-secondary, #a1a1aa);
    padding: 4px;
    margin-left: auto;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: transform 0.2s ease;
    flex-shrink: 0;
}

.dashboard-recap-expand.is-expanded {
    transform: rotate(180deg);
}

.dashboard-recap-details {
    overflow: hidden;
}

.dashboard-recap-details-inner {
    padding-top: 10px;
    margin-top: 8px;
    border-top: 1px solid var(--border-card);
    display: flex;
    flex-direction: column;
    gap: 10px;
}

.dashboard-recap-detail {
    display: flex;
    flex-direction: column;
    gap: 3px;
}

.dashboard-recap-detail-heading {
    font-family: 'Outfit', sans-serif;
    font-size: 11px;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.3px;
    color: var(--text-secondary, #a1a1aa);
}

.dashboard-recap-detail-text {
    font-size: 13px;
    color: var(--text-primary, #1a1a1a);
    margin: 0;
    line-height: 1.4;
}

.dashboard-recap-detail-user {
    display: flex;
    align-items: center;
    gap: 8px;
}

.dashboard-recap-detail-avatar {
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
    flex-shrink: 0;
}

