 273→            ? normalizeWhitespace(
 274→                doc.snippets
 275→                    .map((snippet) => (typeof snippet?.text === 'string' ? snippet.text : ''))
 276→                    .join(' ')
 277→            )
 278→            : '';
 279→
 280→        let image = null;
 281→        if (Array.isArray(doc?.images)) {
 282→            const first = doc.images.find((img) => imageFromNodeLike(img));
 283→            if (first) image = imageFromNodeLike(first);
 284→        }
 285→
 286→        return { text, image };
 287→    } catch {
 288→        return { text: '', image: null };
 289→    }
