1011→            count: stat.count,
1012→            avgDurationMs: stat.count > 0 ? Number((stat.totalDurationMs / stat.count).toFixed(2)) : 0,
1013→            maxDurationMs: Number(stat.maxDurationMs.toFixed(2)),
1014→            bytesSent: stat.bytesSent,
1015→            statusBuckets: stat.statusBuckets,
1016→        }))
1017→        .sort((a, b) => b.count - a.count);
1018→
1019→    return {
1020→        startedAt: metricsState.startedAt,
1021→        requests: metricsState.requests,
1022→        responses: metricsState.responses,
1023→        inFlight: metricsState.inFlight,
1024→        bytesSent: metricsState.bytesSent,
1025→        statusBuckets: metricsState.statusBuckets,
1026→        routeStats: routeStats,
