238→export const repostService = async(sourceJournalId, caption, userId) => {
239→    if(!sourceJournalId || !userId){
240→        throw {status: 400, error: 'sourceJournalId or userId is undefined'};
241→    }
242→
243→    if(caption && caption.length > 280){
244→        throw {status: 400, error: 'caption must be 280 characters or less'};
245→    }
246→
247→    // Fetch source journal
248→    const {data: sourceJournal, error: errorSourceJournal} = await supabase
249→        .from('journals')
250→        .select('id, title, user_id, privacy, is_repost, repost_source_journal_id')
251→        .eq('id', sourceJournalId)
252→        .maybeSingle();
253→
254→    if(errorSourceJournal){
255→        console.error('supabase error while fetching source journal:', errorSourceJournal.message);
256→        throw {status: 500, error: 'supabase error while fetching source journal'};
257→    }
258→
259→    if(!sourceJournal){
260→        throw {status: 404, error: 'source journal not found'};
261→    }
262→
263→    if(sourceJournal.privacy !== 'public'){
264→        throw {status: 403, error: 'cannot repost a private post'};
265→    }
266→
267→    if(sourceJournal.user_id === userId){
268→        throw {status: 403, error: 'cannot repost your own post'};
269→    }
270→
271→    // If reposting a repost, follow chain to the ultimate original
272→    let ultimateSourceId = sourceJournalId;
273→    let ultimateSourceUserId = sourceJournal.user_id;
274→    let ultimateSourceTitle = sourceJournal.title;
275→
276→    if(sourceJournal.is_repost && sourceJournal.repost_source_journal_id){
277→        const {data: originalJournal, error: errorOriginal} = await supabase
278→            .from('journals')
279→            .select('id, title, user_id, privacy')
280→            .eq('id', sourceJournal.repost_source_journal_id)
281→            .maybeSingle();
282→
283→        if(errorOriginal){
284→            console.error('supabase error fetching original:', errorOriginal.message);
285→            throw {status: 500, error: 'supabase error while fetching original post'};
286→        }
287→        if(!originalJournal){
288→            throw {status: 404, error: 'original post no longer exists'};
289→        }
290→        if(originalJournal.privacy !== 'public'){
291→            throw {status: 403, error: 'cannot repost a private post'};
292→        }
293→        if(originalJournal.user_id === userId){
294→            throw {status: 403, error: 'cannot repost your own post'};
295→        }
296→
297→        ultimateSourceId = originalJournal.id;
298→        ultimateSourceUserId = originalJournal.user_id;
299→        ultimateSourceTitle = originalJournal.title;
300→    }
301→
302→    // Check for duplicate repost
303→    const {data: existingRepost, error: errorExisting} = await supabase
304→        .from('journals')
305→        .select('id')
306→        .eq('user_id', userId)
307→        .eq('repost_source_journal_id', ultimateSourceId)
308→        .eq('is_repost', true)
309→        .maybeSingle();
310→
311→    if(errorExisting){
312→        console.error('supabase error while checking existing repost:', errorExisting.message);
313→        throw {status: 500, error: 'supabase error while checking existing repost'};
314→    }
315→
316→    if(existingRepost){
317→        throw {status: 409, error: 'you have already reposted this post'};
318→    }
319→
320→    const repostTitle = `Repost: ${ultimateSourceTitle || 'Untitled'}`;
321→
322→    const {data: insertedRepost, error: errorInsertRepost} = await supabase
323→        .from('journals')
324→        .insert({
325→            user_id: userId,
326→            is_repost: true,
327→            repost_source_journal_id: ultimateSourceId,
328→            repost_caption: caption || null,
329→            post_type: 'text',
330→            content: null,
331→            title: repostTitle.length > 255 ? repostTitle.substring(0, 255) : repostTitle,
332→            privacy: 'public'
333→        })
334→        .select('id')
335→        .single();
336→
337→    if(errorInsertRepost){
338→        console.error('supabase error while inserting repost:', errorInsertRepost.message);
339→        throw {status: 500, error: 'supabase error while inserting repost'};
340→    }
341→
342→    // Notify the original author (skip if self)
343→    const isOwnContent = userId === ultimateSourceUserId;
344→    if(!isOwnContent){
345→        const {error: errorNotif} = await supabase
346→            .from('notifications')
347→            .insert({
348→                sender_id: userId,
349→                receiver_id: ultimateSourceUserId,
350→                journal_id: ultimateSourceId,
351→                repost_journal_id: insertedRepost.id,
352→                type: 'repost',
353→                read: false
354→            });
355→
356→        if(errorNotif){
357→            console.error('supabase error while inserting repost notification:', errorNotif.message);
358→        }
359→    }
360→
361→    return {message: 'repost created', repostId: insertedRepost.id, sourceJournalId: ultimateSourceId};
362→}
