  3→const FREEDOM_WALL_ITEM_TYPES = ["doodle", "sticker", "stamp", "note"];
  4→const REPORTABLE_ITEM_TYPES = ["doodle"];
  5→const DEFAULT_ITEMS_LIMIT = 200;
  6→const MAX_ITEMS_LIMIT = 400;
  7→const DEFAULT_WEEKS_LIMIT = 8;
  8→const MAX_WEEKS_LIMIT = 52;
  9→const NOTE_FONT_STYLES = ["normal", "bold", "italic"];
 10→const NOTE_FONT_FAMILIES = [
 11→    "Georgia",
 12→    "Courier New",
 13→    "Trebuchet MS",
 14→    "Arial",
 15→    "Times New Roman"
 16→];
 17→
 18→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
 19→
 20→const parseLimit = (limit) => {
 21→    const parsedLimit = Number(limit ?? DEFAULT_ITEMS_LIMIT);
 22→    if(Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > MAX_ITEMS_LIMIT){
 23→        throw {status: 400, error: `limit should be an integer between 1 and ${MAX_ITEMS_LIMIT}`};
 24→    }
 25→    return Math.floor(parsedLimit);
 26→};
 27→
 28→const parseWeeksLimit = (limit) => {
 29→    const parsedLimit = Number(limit ?? DEFAULT_WEEKS_LIMIT);
 30→    if(Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > MAX_WEEKS_LIMIT){
 31→        throw {status: 400, error: `limit should be an integer between 1 and ${MAX_WEEKS_LIMIT}`};
 32→    }
 33→    return Math.floor(parsedLimit);
 34→};
 35→
 36→const parseTypeFilters = (types) => {
 37→    if(!types){
 38→        return [];
 39→    }
 40→
 41→    const parsedTypes = String(types)
 42→        .split(",")
 43→        .map((value) => value.trim().toLowerCase())
 44→        .filter(Boolean);
 45→
 46→    const uniqueTypes = [...new Set(parsedTypes)].filter((type) => FREEDOM_WALL_ITEM_TYPES.includes(type));
 47→    return uniqueTypes;
 48→};
 49→
 50→const parseColor = (value, fallback) => {
 51→    if(typeof value !== "string"){
 52→        return fallback;
 53→    }
 54→
 55→    const trimmed = value.trim();
 56→    if(!trimmed){
 57→        return fallback;
 58→    }
 59→
 60→    return trimmed;
 61→};
 62→
 63→const normalizeNumber = (value, fallback) => {
 64→    const parsedValue = Number(value);
 65→    if(Number.isNaN(parsedValue)){
 66→        return fallback;
 67→    }
 68→    return parsedValue;
 69→};
 70→
 71→const normalizePosition = (value, fallback) => clamp(normalizeNumber(value, fallback), 0, 1);
 72→
 73→const sanitizeDoodlePayload = (payload) => {
 74→    const points = Array.isArray(payload?.points)
 75→        ? payload.points
 76→            .map((point) => Number(point))
 77→            .filter((point) => !Number.isNaN(point))
 78→            .map((point) => clamp(point, 0, 1))
 79→        : [];
 80→
 81→    if(points.length < 4){
 82→        throw {status: 400, error: "doodle payload points must contain at least 2 coordinate pairs"};
 83→    }
 84→
 85→    const sanitizedPoints = points.length % 2 === 0
 86→        ? points
 87→        : points.slice(0, -1);
 88→
 89→    const normalizedSize = clamp(normalizeNumber(payload?.size, 2.8), 1, 24);
 90→    const result = {
 91→        points: sanitizedPoints,
 92→        color: parseColor(payload?.color, "#5f92ff"),
 93→        size: normalizedSize,
 94→        // Backward compatibility for older DB check constraints that still expect strokeWidth.
 95→        strokeWidth: normalizedSize
 96→    };
 97→
 98→    if(Array.isArray(payload?.widths)){
 99→        const sanitizedWidths = payload.widths
100→            .map((w) => Number(w))
101→            .filter((w) => !Number.isNaN(w))
102→            .map((w) => clamp(w, 0.1, 3.0));
103→        if(sanitizedWidths.length > 0){
104→            result.widths = sanitizedWidths;
105→        }
106→    }
107→
108→    return result;
109→};
110→
111→const sanitizeStickerPayload = (payload) => {
112→    const sticker = typeof payload?.sticker === "string" ? payload.sticker.trim() : "";
113→    const stickerId = typeof payload?.stickerId === "string" ? payload.stickerId.trim() : "";
114→    if(!sticker && !stickerId){
115→        throw {status: 400, error: "sticker payload requires sticker or stickerId"};
116→    }
117→
118→    const result = {
119→        x: normalizePosition(payload?.x, 0.5),
120→        y: normalizePosition(payload?.y, 0.5),
121→        scale: clamp(normalizeNumber(payload?.scale, 1), 0.25, 6),
122→        rotation: clamp(normalizeNumber(payload?.rotation, 0), -360, 360)
123→    };
124→
125→    if(sticker){
126→        result.sticker = sticker;
127→    } else {
128→        result.stickerId = stickerId;
129→    }
130→
131→    return result;
132→};
133→
134→const sanitizeStampPayload = (payload) => {
135→    const stamp = typeof payload?.stamp === "string" ? payload.stamp.trim() : "";
136→    if(!stamp){
137→        throw {status: 400, error: "stamp payload requires stamp"};
138→    }
139→
140→    return {
141→        stamp: stamp,
142→        x: normalizePosition(payload?.x, 0.5),
143→        y: normalizePosition(payload?.y, 0.5),
144→        scale: clamp(normalizeNumber(payload?.scale, 1), 0.35, 5),
145→        rotation: clamp(normalizeNumber(payload?.rotation, 0), -360, 360)
146→    };
147→};
148→
149→const sanitizeNotePayload = (payload) => {
150→    const text = typeof payload?.text === "string" ? payload.text.trim() : "";
151→    if(!text){
152→        throw {status: 400, error: "note payload requires text"};
153→    }
154→
155→    const requestedFontFamily = typeof payload?.fontFamily === "string" ? payload.fontFamily.trim() : "";
156→    const requestedFontStyle = typeof payload?.fontStyle === "string" ? payload.fontStyle.trim().toLowerCase() : "";
157→
158→    return {
159→        text: text.slice(0, 800),
160→        x: normalizePosition(payload?.x, 0.45),
161→        y: normalizePosition(payload?.y, 0.45),
162→        width: clamp(normalizeNumber(payload?.width, 0.26), 0.12, 0.9),
163→        height: clamp(normalizeNumber(payload?.height, 0.2), 0.1, 0.8),
164→        rotation: clamp(normalizeNumber(payload?.rotation, 0), -360, 360),
165→        fontFamily: NOTE_FONT_FAMILIES.includes(requestedFontFamily) ? requestedFontFamily : "Arial",
166→        fontStyle: NOTE_FONT_STYLES.includes(requestedFontStyle) ? requestedFontStyle : "normal",
167→        fontColor: parseColor(payload?.fontColor, "#1f2937"),
168→        bgColor: parseColor(payload?.bgColor, "#fff4a8"),
169→        fontSize: clamp(normalizeNumber(payload?.fontSize, 16), 10, 64)
170→    };
171→};
172→
173→const sanitizePayloadByType = (itemType, payload) => {
174→    if(!payload || typeof payload !== "object" || Array.isArray(payload)){
175→        throw {status: 400, error: "payload should be an object"};
176→    }
177→
178→    if(itemType === "doodle"){
179→        return sanitizeDoodlePayload(payload);
180→    }
181→    if(itemType === "sticker"){
