358→    if(!userId){
359→        throw {status: 401, error: "not authorized"};
360→    }
361→
362→    if(!weekId){
363→        throw {status: 400, error: "weekId is required"};
364→    }
365→
366→    const normalizedType = typeof itemType === "string" ? itemType.trim().toLowerCase() : "";
367→    if(!FREEDOM_WALL_ITEM_TYPES.includes(normalizedType)){
368→        throw {status: 400, error: "invalid freedom wall item type"};
369→    }
370→
371→    await assertActiveWeek(weekId);
372→
373→    const sanitizedPayload = sanitizePayloadByType(normalizedType, payload);
374→    const parsedZIndex = clamp(normalizeNumber(zIndex, 0), -100000, 100000);
375→
376→    const {data: createdItem, error: createError} = await supabase
377→        .from("freedom_wall_items")
378→        .insert({
379→            week_id: weekId,
380→            user_id: userId,
381→            item_type: normalizedType,
382→            payload: sanitizedPayload,
383→            z_index: parsedZIndex
384→        })
385→        .select(selectItemColumns)
386→        .single();
387→
388→    if(createError){
389→        console.error("supabase error while creating freedom wall item:", createError.message);
390→        throwMappedDatabaseError(createError, "failed to create freedom wall item");
391→    }
392→
393→    return {item: createdItem};
394→};
