  3→export const requestConstellationService = async (senderId, starIdA, starIdB, label) => {
  4→    if (!senderId || !starIdA || !starIdB) {
  5→        throw { status: 400, error: 'senderId, starIdA, and starIdB are required' };
  6→    }
  7→
  8→    // Verify starIdA belongs to sender
  9→    const { data: starA, error: errorStarA } = await supabase
 10→        .from('journals')
 11→        .select('id, user_id')
 12→        .eq('id', starIdA)
 13→        .maybeSingle();
 14→
 15→    if (errorStarA) {
 16→        console.error('supabase error checking starA ownership:', errorStarA.message);
 17→        throw { status: 500, error: 'error checking star ownership' };
 18→    }
 19→    if (!starA || starA.user_id !== senderId) {
 20→        throw { status: 403, error: 'starIdA does not belong to you' };
 21→    }
 22→
 23→    // Get starIdB owner
 24→    const { data: starB, error: errorStarB } = await supabase
 25→        .from('journals')
 26→        .select('id, user_id')
 27→        .eq('id', starIdB)
 28→        .maybeSingle();
 29→
 30→    if (errorStarB) {
 31→        console.error('supabase error checking starB:', errorStarB.message);
 32→        throw { status: 500, error: 'error checking target star' };
 33→    }
 34→    if (!starB) {
 35→        throw { status: 404, error: 'target star not found' };
 36→    }
 37→
 38→    const receiverId = starB.user_id;
 39→    if (receiverId === senderId) {
 40→        throw { status: 400, error: 'cannot create constellation with your own stars' };
 41→    }
 42→
 43→    // Normalize pair order to avoid duplicate check issues
 44→    const [normA, normB] = starIdA < starIdB ? [starIdA, starIdB] : [starIdB, starIdA];
 45→    const [normUserA, normUserB] = starIdA < starIdB ? [senderId, receiverId] : [receiverId, senderId];
 46→
 47→    // Insert constellation
 48→    const { data: constellation, error: errorInsert } = await supabase
 49→        .from('constellations')
 50→        .insert({
 51→            star_id_a: normA,
 52→            star_id_b: normB,
 53→            user_id_a: normUserA,
 54→            user_id_b: normUserB,
 55→            label: label || '',
 56→            status: 'pending',
 57→        })
 58→        .select()
 59→        .single();
 60→
 61→    if (errorInsert) {
 62→        if (errorInsert.code === '23505') {
 63→            throw { status: 409, error: 'a constellation link between these stars already exists' };
 64→        }
 65→        console.error('supabase error inserting constellation:', errorInsert.message);
 66→        throw { status: 500, error: 'error creating constellation' };
 67→    }
 68→
 69→    // Insert notification for the receiver
 70→    const { error: errorNotif } = await supabase
 71→        .from('notifications')
 72→        .insert({
 73→            sender_id: senderId,
 74→            receiver_id: receiverId,
 75→            journal_id: starIdB,
 76→            type: 'constellation_request',
 77→            constellation_id: constellation.id,
 78→            read: false,
 79→        });
 80→
 81→    if (errorNotif) {
 82→        console.error('supabase error inserting constellation notification:', errorNotif.message);
 83→    }
 84→
 85→    return { message: 'constellation request sent', constellationId: constellation.id };
 86→};
