  3→// ── Hash helpers (mirror client-side userHomeCoords) ──────────────────
  4→const simpleHash = (str) => {
  5→    let h = 0;
  6→    for (let i = 0; i < str.length; i++) {
  7→        h = ((h << 5) - h + str.charCodeAt(i)) | 0;
  8→    }
  9→    return Math.abs(h);
 10→};
 11→
 12→const userHomeCoords = (userId) => {
 13→    const mid = Math.floor(userId.length / 2);
 14→    const xHash = simpleHash(userId.slice(0, mid));
 15→    const yHash = simpleHash(userId.slice(mid));
 16→    const x = (xHash % 50001) / 50000 * 50000 - 25000;
 17→    const y = (yHash % 50001) / 50000 * 50000 - 25000;
 18→    return { x, y };
 19→};
 20→
 21→const spiralLayout = (index) => {
 22→    if (index === 0) return { dx: 0, dy: 0 };
 23→    const angle = index * 0.8;
 24→    const radius = 30 * Math.sqrt(index);
 25→    return { dx: radius * Math.cos(angle), dy: radius * Math.sin(angle) };
 26→};
 27→
 28→// ── Physics constants ─────────────────────────────────────────────────
 29→const REPULSION_K = 5e8;
 30→const ATTRACTION_K = 0.0005;
 31→const BOUNDARY = 25000;
 32→const MAX_ITERATIONS = 200;
 33→const INITIAL_TEMP = 1.0;
 34→const COOLING = 0.97;
 35→const DAMPING = 0.9;
 36→const STAR_PULL_MAX = 80;
 37→
 38→// ── Dot product for normalized vectors ────────────────────────────────
 39→const dot = (a, b) => {
 40→    let sum = 0;
 41→    for (let i = 0; i < a.length; i++) sum += a[i] * b[i];
 42→    return sum;
 43→};
 44→
 45→// ══════════════════════════════════════════════════════════════════════
 46→// Step 1: Recompute all galaxy centroids
 47→// ══════════════════════════════════════════════════════════════════════
 48→export async function recomputeAllCentroids() {
 49→    // Get all users who have public posts with embeddings
 50→    const { data: users, error: usersErr } = await supabase
 51→        .from('journals')
 52→        .select('user_id')
 53→        .eq('privacy', 'public')
 54→        .not('embeddings', 'is', null);
 55→
 56→    if (usersErr) throw new Error(`Failed to query users: ${usersErr.message}`);
 57→
 58→    const uniqueUserIds = [...new Set((users || []).map(u => u.user_id))];
 59→    console.log(`[galaxy-settle] Found ${uniqueUserIds.length} users with embeddings`);
 60→
 61→    let upserted = 0;
 62→    for (const userId of uniqueUserIds) {
 63→        // Compute mean embedding via RPC or manual fetch
 64→        const { data: posts, error: postsErr } = await supabase
 65→            .from('journals')
 66→            .select('embeddings')
 67→            .eq('user_id', userId)
 68→            .eq('privacy', 'public')
 69→            .not('embeddings', 'is', null);
 70→
 71→        if (postsErr || !posts || posts.length === 0) continue;
 72→
 73→        // Compute mean embedding
 74→        const dim = 384;
 75→        const mean = new Array(dim).fill(0);
 76→        for (const post of posts) {
 77→            const emb = post.embeddings;
 78→            if (!emb || emb.length !== dim) continue;
 79→            for (let i = 0; i < dim; i++) mean[i] += emb[i];
 80→        }
 81→        for (let i = 0; i < dim; i++) mean[i] /= posts.length;
 82→
 83→        // Normalize the mean embedding
 84→        let norm = 0;
 85→        for (let i = 0; i < dim; i++) norm += mean[i] * mean[i];
 86→        norm = Math.sqrt(norm);
 87→        if (norm > 0) {
 88→            for (let i = 0; i < dim; i++) mean[i] /= norm;
 89→        }
 90→
 91→        // Format as pgvector string
 92→        const vectorStr = `[${mean.join(',')}]`;
 93→
 94→        const { error: upsertErr } = await supabase
 95→            .from('galaxy_centroids')
 96→            .upsert({
 97→                user_id: userId,
 98→                mean_embedding: vectorStr,
 99→                post_count: posts.length,
100→                updated_at: new Date().toISOString()
101→            }, { onConflict: 'user_id' });
102→
103→        if (upsertErr) {
104→            console.error(`[galaxy-settle] Failed to upsert centroid for ${userId}:`, upsertErr.message);
105→        } else {
106→            upserted++;
107→        }
108→    }
109→
110→    console.log(`[galaxy-settle] Upserted ${upserted} centroids`);
111→    return upserted;
112→}
113→
114→// ══════════════════════════════════════════════════════════════════════
115→// Step 2: Recompute galaxy edges (similarity between centroids)
116→// ══════════════════════════════════════════════════════════════════════
117→export async function recomputeGalaxyEdges() {
118→    const { data: centroids, error } = await supabase
119→        .from('galaxy_centroids')
120→        .select('user_id, mean_embedding')
121→        .not('mean_embedding', 'is', null);
122→
123→    if (error) throw new Error(`Failed to fetch centroids: ${error.message}`);
124→    if (!centroids || centroids.length < 2) {
125→        console.log('[galaxy-settle] Not enough centroids for edges');
126→        return 0;
127→    }
128→
129→    const THRESHOLD = 0.25;
130→    const edges = [];
131→
132→    for (let i = 0; i < centroids.length; i++) {
133→        for (let j = i + 1; j < centroids.length; j++) {
134→            const a = centroids[i];
135→            const b = centroids[j];
136→
137→            // Parse embeddings (they come as arrays from Supabase)
138→            const embA = Array.isArray(a.mean_embedding) ? a.mean_embedding : null;
139→            const embB = Array.isArray(b.mean_embedding) ? b.mean_embedding : null;
140→            if (!embA || !embB) continue;
141→
142→            const similarity = dot(embA, embB);
143→            if (similarity >= THRESHOLD) {
144→                // Ensure user_a < user_b
145→                const [userA, userB] = a.user_id < b.user_id
146→                    ? [a.user_id, b.user_id]
147→                    : [b.user_id, a.user_id];
148→                edges.push({ user_a: userA, user_b: userB, similarity });
149→            }
150→        }
151→    }
152→
153→    // Clear old edges and insert new ones
154→    await supabase.from('galaxy_edges').delete().neq('similarity', -999);
155→
156→    if (edges.length > 0) {
157→        // Batch insert in chunks of 500
158→        for (let i = 0; i < edges.length; i += 500) {
159→            const chunk = edges.slice(i, i + 500);
160→            const { error: insertErr } = await supabase
161→                .from('galaxy_edges')
162→                .upsert(chunk, { onConflict: 'user_a,user_b' });
163→            if (insertErr) {
164→                console.error('[galaxy-settle] Edge insert error:', insertErr.message);
165→            }
166→        }
167→    }
168→
169→    console.log(`[galaxy-settle] Computed ${edges.length} galaxy edges`);
170→    return edges.length;
171→}
172→
173→// ══════════════════════════════════════════════════════════════════════
174→// Step 3: Force-directed galaxy position settle
175→// ══════════════════════════════════════════════════════════════════════
176→export async function settleGalaxyPositions() {
177→    const { data: centroids, error: centErr } = await supabase
178→        .from('galaxy_centroids')
179→        .select('user_id, post_count');
180→
181→    if (centErr) throw new Error(`Failed to fetch centroids: ${centErr.message}`);
182→    if (!centroids || centroids.length === 0) return;
183→
184→    const { data: edges, error: edgeErr } = await supabase
185→        .from('galaxy_edges')
186→        .select('user_a, user_b, similarity');
187→
188→    if (edgeErr) throw new Error(`Failed to fetch edges: ${edgeErr.message}`);
189→
190→    // Initialize positions from hash-based coords
191→    const nodes = new Map();
192→    for (const c of centroids) {
193→        const home = userHomeCoords(c.user_id);
194→        nodes.set(c.user_id, {
195→            x: home.x,
196→            y: home.y,
197→            vx: 0,
198→            vy: 0,
199→            count: c.post_count || 1,
200→        });
201→    }
202→
203→    const nodeIds = Array.from(nodes.keys());
204→    let temperature = INITIAL_TEMP;
205→
206→    for (let iter = 0; iter < MAX_ITERATIONS; iter++) {
207→        // Reset forces
208→        const forces = new Map();
209→        for (const id of nodeIds) forces.set(id, { fx: 0, fy: 0 });
210→
211→        // Repulsion: all pairs
212→        for (let i = 0; i < nodeIds.length; i++) {
213→            for (let j = i + 1; j < nodeIds.length; j++) {
214→                const a = nodes.get(nodeIds[i]);
215→                const b = nodes.get(nodeIds[j]);
216→                const dx = b.x - a.x;
217→                const dy = b.y - a.y;
218→                const distSq = dx * dx + dy * dy;
219→                const dist = Math.sqrt(distSq) || 1;
220→
221→                const force = REPULSION_K * (a.count + b.count) / distSq;
222→                const fx = (dx / dist) * force;
223→                const fy = (dy / dist) * force;
224→
225→                const fa = forces.get(nodeIds[i]);
226→                const fb = forces.get(nodeIds[j]);
227→                fa.fx -= fx;
228→                fa.fy -= fy;
229→                fb.fx += fx;
230→                fb.fy += fy;
231→            }
232→        }
233→
234→        // Attraction: edge pairs (spring force)
235→        if (edges) {
236→            for (const edge of edges) {
237→                const a = nodes.get(edge.user_a);
238→                const b = nodes.get(edge.user_b);
239→                if (!a || !b) continue;
240→
241→                const dx = b.x - a.x;
242→                const dy = b.y - a.y;
243→                const dist = Math.sqrt(dx * dx + dy * dy) || 1;
244→                const idealDist = 2000 * (1 - edge.similarity);
245→                const force = ATTRACTION_K * edge.similarity * (dist - idealDist);
246→                const fx = (dx / dist) * force;
247→                const fy = (dy / dist) * force;
248→
249→                const fa = forces.get(edge.user_a);
250→                const fb = forces.get(edge.user_b);
251→                fa.fx += fx;
252→                fa.fy += fy;
253→                fb.fx -= fx;
254→                fb.fy -= fy;
255→            }
256→        }
257→
258→        // Apply forces with cooling and damping
259→        let maxDisp = 0;
260→        for (const id of nodeIds) {
261→            const node = nodes.get(id);
262→            const f = forces.get(id);
263→
264→            node.vx = (node.vx + f.fx) * DAMPING;
265→            node.vy = (node.vy + f.fy) * DAMPING;
266→
267→            const dispX = node.vx * temperature;
268→            const dispY = node.vy * temperature;
269→
270→            node.x += dispX;
271→            node.y += dispY;
272→
273→            // Soft boundary
274→            if (node.x > BOUNDARY) node.x = BOUNDARY - (node.x - BOUNDARY) * 0.5;
275→            if (node.x < -BOUNDARY) node.x = -BOUNDARY - (node.x + BOUNDARY) * 0.5;
276→            if (node.y > BOUNDARY) node.y = BOUNDARY - (node.y - BOUNDARY) * 0.5;
277→            if (node.y < -BOUNDARY) node.y = -BOUNDARY - (node.y + BOUNDARY) * 0.5;
278→
279→            const disp = Math.sqrt(dispX * dispX + dispY * dispY);
280→            if (disp > maxDisp) maxDisp = disp;
281→        }
282→
283→        temperature *= COOLING;
284→
285→        if (maxDisp < 1.0) {
286→            console.log(`[galaxy-settle] Converged at iteration ${iter}`);
287→            break;
288→        }
289→    }
290→
291→    // Write settled positions to galaxy_centroids
292→    for (const id of nodeIds) {
293→        const node = nodes.get(id);
294→        const { error: updateErr } = await supabase
295→            .from('galaxy_centroids')
296→            .update({
297→                galaxy_x: Math.round(node.x * 100) / 100,
298→                galaxy_y: Math.round(node.y * 100) / 100,
299→                updated_at: new Date().toISOString()
300→            })
301→            .eq('user_id', id);
302→
303→        if (updateErr) {
304→            console.error(`[galaxy-settle] Failed to update position for ${id}:`, updateErr.message);
305→        }
306→    }
307→
308→    console.log(`[galaxy-settle] Settled ${nodeIds.length} galaxy positions`);
309→}
310→
311→// ══════════════════════════════════════════════════════════════════════
312→// Step 4: Settle star (post) positions within galaxies
313→// ══════════════════════════════════════════════════════════════════════
314→export async function settleStarPositions() {
315→    const { data: centroids, error: centErr } = await supabase
316→        .from('galaxy_centroids')
317→        .select('user_id, galaxy_x, galaxy_y, mean_embedding')
318→        .not('galaxy_x', 'is', null);
319→
320→    if (centErr) throw new Error(`Failed to fetch centroids: ${centErr.message}`);
321→    if (!centroids || centroids.length === 0) return;
322→
323→    const centroidMap = new Map();
324→    for (const c of centroids) {
325→        centroidMap.set(c.user_id, c);
326→    }
327→
328→    // Fetch edges for neighbor lookups
329→    const { data: edges } = await supabase
330→        .from('galaxy_edges')
331→        .select('user_a, user_b, similarity')
332→        .gte('similarity', 0.3);
333→
334→    // Build neighbor map
335→    const neighbors = new Map();
336→    for (const e of (edges || [])) {
337→        if (!neighbors.has(e.user_a)) neighbors.set(e.user_a, []);
338→        if (!neighbors.has(e.user_b)) neighbors.set(e.user_b, []);
339→        neighbors.get(e.user_a).push({ userId: e.user_b, similarity: e.similarity });
340→        neighbors.get(e.user_b).push({ userId: e.user_a, similarity: e.similarity });
341→    }
342→
343→    let totalUpdated = 0;
344→
345→    for (const [userId, centroid] of centroidMap) {
346→        // Fetch this user's public posts with embeddings
347→        const { data: posts, error: postsErr } = await supabase
348→            .from('journals')
349→            .select('id, embeddings')
350→            .eq('user_id', userId)
351→            .eq('privacy', 'public')
352→            .not('embeddings', 'is', null)
353→            .order('created_at', { ascending: true });
354→
355→        if (postsErr || !posts || posts.length === 0) continue;
356→
357→        const galaxyNeighbors = neighbors.get(userId) || [];
358→        const neighborCentroids = galaxyNeighbors
359→            .map(n => centroidMap.get(n.userId))
360→            .filter(Boolean);
361→
362→        for (let idx = 0; idx < posts.length; idx++) {
363→            const post = posts[idx];
364→            const offset = spiralLayout(idx);
365→            let baseX = centroid.galaxy_x + offset.dx;
366→            let baseY = centroid.galaxy_y + offset.dy;
367→
368→            // Compute gravity pulls from neighboring galaxy centroids
369→            let pullX = 0;
370→            let pullY = 0;
371→
372→            if (post.embeddings && Array.isArray(post.embeddings)) {
373→                for (const nc of neighborCentroids) {
374→                    if (!nc.mean_embedding || !Array.isArray(nc.mean_embedding)) continue;
375→
376→                    const similarity = dot(post.embeddings, nc.mean_embedding);
377→                    if (similarity < 0.4) continue;
378→
379→                    const strength = (similarity - 0.4) * STAR_PULL_MAX;
380→                    const dx = nc.galaxy_x - baseX;
381→                    const dy = nc.galaxy_y - baseY;
382→                    const dist = Math.sqrt(dx * dx + dy * dy) || 1;
383→
384→                    pullX += (dx / dist) * strength;
385→                    pullY += (dy / dist) * strength;
386→                }
387→            }
388→
389→            // Clamp total pull
390→            const pullMag = Math.sqrt(pullX * pullX + pullY * pullY);
391→            if (pullMag > STAR_PULL_MAX) {
392→                pullX = (pullX / pullMag) * STAR_PULL_MAX;
393→                pullY = (pullY / pullMag) * STAR_PULL_MAX;
394→            }
395→
396→            const settledX = Math.round((baseX + pullX) * 100) / 100;
397→            const settledY = Math.round((baseY + pullY) * 100) / 100;
398→
399→            const { error: updateErr } = await supabase
400→                .from('journals')
401→                .update({ settled_x: settledX, settled_y: settledY })
402→                .eq('id', post.id);
403→
404→            if (!updateErr) totalUpdated++;
405→        }
406→    }
407→
408→    console.log(`[galaxy-settle] Settled ${totalUpdated} star positions`);
409→}
410→
411→// ══════════════════════════════════════════════════════════════════════
412→// Step 5: Incremental settle for a single user
413→// ══════════════════════════════════════════════════════════════════════
414→export async function incrementalSettleForUser(userId) {
415→    if (!userId) return;
416→
417→    try {
418→        // 1. Recompute this user's centroid
419→        const { data: posts } = await supabase
420→            .from('journals')
421→            .select('embeddings')
422→            .eq('user_id', userId)
423→            .eq('privacy', 'public')
424→            .not('embeddings', 'is', null);
425→
426→        if (!posts || posts.length === 0) return;
427→
428→        const dim = 384;
429→        const mean = new Array(dim).fill(0);
430→        let validCount = 0;
431→        for (const post of posts) {
432→            const emb = post.embeddings;
433→            if (!emb || emb.length !== dim) continue;
434→            for (let i = 0; i < dim; i++) mean[i] += emb[i];
435→            validCount++;
436→        }
437→        if (validCount === 0) return;
438→
439→        for (let i = 0; i < dim; i++) mean[i] /= validCount;
440→
441→        // Normalize
442→        let norm = 0;
443→        for (let i = 0; i < dim; i++) norm += mean[i] * mean[i];
444→        norm = Math.sqrt(norm);
445→        if (norm > 0) {
446→            for (let i = 0; i < dim; i++) mean[i] /= norm;
447→        }
448→
449→        const vectorStr = `[${mean.join(',')}]`;
450→
451→        // Get or create initial position from hash
452→        const { data: existing } = await supabase
453→            .from('galaxy_centroids')
454→            .select('galaxy_x, galaxy_y')
455→            .eq('user_id', userId)
456→            .single();
457→
458→        const home = userHomeCoords(userId);
459→
460→        await supabase.from('galaxy_centroids').upsert({
461→            user_id: userId,
462→            mean_embedding: vectorStr,
463→            galaxy_x: existing?.galaxy_x ?? home.x,
464→            galaxy_y: existing?.galaxy_y ?? home.y,
465→            post_count: validCount,
466→            updated_at: new Date().toISOString()
467→        }, { onConflict: 'user_id' });
468→
469→        // 2. Recompute edges for this user against all other centroids
470→        const { data: allCentroids } = await supabase
471→            .from('galaxy_centroids')
472→            .select('user_id, mean_embedding')
473→            .not('mean_embedding', 'is', null)
474→            .neq('user_id', userId);
475→
476→        if (allCentroids && allCentroids.length > 0) {
477→            const newEdges = [];
478→            for (const other of allCentroids) {
479→                const embB = Array.isArray(other.mean_embedding) ? other.mean_embedding : null;
480→                if (!embB) continue;
481→
482→                const similarity = dot(mean, embB);
483→                if (similarity >= 0.25) {
484→                    const [userA, userB] = userId < other.user_id
485→                        ? [userId, other.user_id]
486→                        : [other.user_id, userId];
487→                    newEdges.push({ user_a: userA, user_b: userB, similarity });
488→                }
489→            }
490→
491→            // Delete old edges involving this user
492→            await supabase.from('galaxy_edges').delete().or(`user_a.eq.${userId},user_b.eq.${userId}`);
493→
494→            if (newEdges.length > 0) {
495→                await supabase.from('galaxy_edges').upsert(newEdges, { onConflict: 'user_a,user_b' });
496→            }
497→        }
498→
499→        // 3. Re-settle this user's star positions (use current galaxy position)
500→        const { data: centroid } = await supabase
501→            .from('galaxy_centroids')
502→            .select('galaxy_x, galaxy_y, mean_embedding')
503→            .eq('user_id', userId)
504→            .single();
505→
506→        if (!centroid || centroid.galaxy_x == null) return;
507→
508→        const { data: userPosts } = await supabase
509→            .from('journals')
510→            .select('id, embeddings')
511→            .eq('user_id', userId)
512→            .eq('privacy', 'public')
513→            .not('embeddings', 'is', null)
514→            .order('created_at', { ascending: true });
515→
516→        if (!userPosts) return;
517→
518→        // Get neighbor centroids
519→        const { data: edges } = await supabase
520→            .from('galaxy_edges')
521→            .select('user_a, user_b, similarity')
522→            .or(`user_a.eq.${userId},user_b.eq.${userId}`)
523→            .gte('similarity', 0.3);
524→
525→        const neighborIds = (edges || []).map(e =>
526→            e.user_a === userId ? e.user_b : e.user_a
527→        );
528→
529→        let neighborCentroids = [];
530→        if (neighborIds.length > 0) {
531→            const { data: ncs } = await supabase
532→                .from('galaxy_centroids')
533→                .select('user_id, galaxy_x, galaxy_y, mean_embedding')
534→                .in('user_id', neighborIds)
535→                .not('galaxy_x', 'is', null);
536→            neighborCentroids = ncs || [];
537→        }
538→
539→        for (let idx = 0; idx < userPosts.length; idx++) {
540→            const post = userPosts[idx];
541→            const offset = spiralLayout(idx);
542→            let baseX = centroid.galaxy_x + offset.dx;
543→            let baseY = centroid.galaxy_y + offset.dy;
544→
545→            let pullX = 0;
546→            let pullY = 0;
547→
548→            if (post.embeddings && Array.isArray(post.embeddings)) {
549→                for (const nc of neighborCentroids) {
550→                    if (!nc.mean_embedding || !Array.isArray(nc.mean_embedding)) continue;
551→                    const sim = dot(post.embeddings, nc.mean_embedding);
552→                    if (sim < 0.4) continue;
553→
554→                    const strength = (sim - 0.4) * STAR_PULL_MAX;
555→                    const dx = nc.galaxy_x - baseX;
556→                    const dy = nc.galaxy_y - baseY;
557→                    const dist = Math.sqrt(dx * dx + dy * dy) || 1;
558→                    pullX += (dx / dist) * strength;
559→                    pullY += (dy / dist) * strength;
560→                }
561→            }
562→
563→            const pullMag = Math.sqrt(pullX * pullX + pullY * pullY);
564→            if (pullMag > STAR_PULL_MAX) {
565→                pullX = (pullX / pullMag) * STAR_PULL_MAX;
566→                pullY = (pullY / pullMag) * STAR_PULL_MAX;
567→            }
568→
569→            await supabase
570→                .from('journals')
571→                .update({
572→                    settled_x: Math.round((baseX + pullX) * 100) / 100,
573→                    settled_y: Math.round((baseY + pullY) * 100) / 100
574→                })
575→                .eq('id', post.id);
576→        }
577→
578→        console.log(`[galaxy-settle] Incremental settle complete for user ${userId}`);
579→    } catch (err) {
580→        console.error('[galaxy-settle] Incremental settle error:', err?.message || err);
581→    }
582→}
583→
584→// ══════════════════════════════════════════════════════════════════════
585→// Full settle orchestrator
586→// ══════════════════════════════════════════════════════════════════════
587→export async function runFullSettle() {
588→    console.log('[galaxy-settle] Starting full settle...');
589→    const start = Date.now();
590→
591→    await recomputeAllCentroids();
592→    await recomputeGalaxyEdges();
593→    await settleGalaxyPositions();
594→    await settleStarPositions();
595→
596→    const elapsed = ((Date.now() - start) / 1000).toFixed(1);
597→    console.log(`[galaxy-settle] Full settle complete in ${elapsed}s`);
598→}
