325→                            onClick={(e) => {
326→                                if (displayType === 'constellation_request' || displayType === 'constellation_accepted') {
327→                                    e.stopPropagation();
328→                                    mutationReadNotif.mutate({ notifId: notification.id, source: notification?.source || 'journal' });
329→                                    navigate('/universe', {
330→                                        state: {
331→                                            flyToConstellation: {
332→                                                starIdA: notification.constellations?.star_id_a,
333→                                                starIdB: notification.constellations?.star_id_b,
334→                                            },
335→                                        },
336→                                    });
337→                                    return;
338→                                }
339→                                handleReadNotif(e, notification);
340→                            }}
341→                            >
342→                                {displayType === 'constellation_request' ? (
343→                                    <div className="notification-content-text">
344→                                        <p className="notif-content-sliced-text">wants to create a constellation link with your star</p>
345→                                        {notification.constellations?.status === 'accepted' ? (
